// // This module inverts the behavior of the clock gating cell. When EN is high, CLK_G is held low; when EN is low, CLK_G follows CLK.
module clock_gate (
  input CLK,
  input EN,
  output reg CLK_G
);

  always @(posedge CLK) begin
    if (EN) begin
      CLK_G <= CLK;
    end
    else begin
      CLK_G <= 1'b0;
    end
  end

endmodule
